// coches.net: 30 coches/página, ~244k → ~8.135 páginas. Techo amplio;
// el loop se corta solo al primer page sin coches (early-exit del IF).
const pages=[];
for(let i=1;i<=8300;i++){ pages.push({ json:{ page:i } }); }
return pages;

// coches.net – transform: HTML ?pg=N → __INITIAL_PROPS__.initialResults.items → UPSERT
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');

// Extraer window.__INITIAL_PROPS__ = JSON.parse("...")
let items = [];
try {
  const marker = 'window.__INITIAL_PROPS__ = JSON.parse(';
  const i = html.indexOf(marker);
  if (i !== -1) {
    let j = i + marker.length;            // apunta a la "
    let k = j + 1, esc = false;
    for (; k < html.length; k++) { const c = html[k]; if (esc) esc = false; else if (c === '\\') esc = true; else if (c === '"') break; }
    const props = JSON.parse(JSON.parse(html.slice(j, k + 1)));
    items = (props.initialResults && props.initialResults.items) || [];
  }
} catch (e) { items = []; }

if (!items.length) {
  return [{ json: { sql: null, count: 0 } }];
}

function normalizeFuel(raw) {
  const s = String(raw || '').toLowerCase();
  if (s.indexOf('diesel') !== -1 || s.indexOf('diésel') !== -1) return 'Diesel';
  if (s.indexOf('electr') !== -1) return 'Eléctrico';
  const enchufable = (s.indexOf('enchufable') !== -1 || s.indexOf('plug') !== -1) && s.indexOf('no enchufable') === -1;
  if (s.indexOf('hibrido') !== -1 || s.indexOf('híbrido') !== -1 || s.indexOf('hybrid') !== -1 || s.indexOf('enchufable') !== -1) return enchufable ? 'Híbrido enchufable' : 'Híbrido';
  if (s.indexOf('gasolina') !== -1 || s.indexOf('petrol') !== -1) return 'Gasolina';
  if (s.indexOf('glp') !== -1 || s.indexOf('gnc') !== -1 || s.indexOf('gas') !== -1) return 'Gas';
  return raw || '';
}

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}

const rows = [];
for (const it of items) {
  const id = 'cn_' + String(it.id);
  const url = it.url ? ('https://www.coches.net' + it.url) : '';
  const brand = it.make || '';
  const model = it.model || '';
  const title = it.title || (brand + ' ' + model).trim();
  const year = (it.year != null) ? String(it.year) : 'NULL';
  const mileage = (it.km != null) ? String(it.km) : 'NULL';
  const fuel = normalizeFuel(it.fuelType);
  const price = (it.price != null) ? String(it.price) : 'NULL';
  const financePrice = (it.financedPrice != null) ? String(it.financedPrice) : 'NULL';
  const powerCv = (it.hp != null && it.hp > 0) ? it.hp : null;
  const powerKw = powerCv ? Math.round(powerCv / 1.35962) : null;
  const imageUrl = it.imgUrl || it.img || '';
  const photosArr = Array.isArray(it.photos) ? it.photos.filter(Boolean).slice(0, 15) : (imageUrl ? [imageUrl] : []);
  const imagesJson = JSON.stringify(photosArr).replace(/'/g, "''");
  const loc = it.location || {};
  const province = loc.mainProvince || loc.regionLiteral || '';
  const sellerType = it.isProfessional ? 'profesional' : 'particular';
  const dealerName = (it.seller && (it.seller.name || it.seller.commercialName)) ? (it.seller.name || it.seller.commercialName) : '';
  const warranty = (it.warrantyMonths != null && it.warrantyMonths > 0) ? String(it.warrantyMonths) : 'NULL';
  const rawPayload = JSON.stringify(it).replace(/'/g, "''");

  const row = '(' +
    esc(id) + ', ' + "'cochesnet', " + esc(url) + ', ' + esc(title) + ', ' + esc(brand) + ', ' + esc(model) + ', ' +
    year + ', ' + mileage + ', ' +
    price + ', ' + financePrice + ', ' +
    esc(fuel) + ', ' +
    esc(imageUrl) + ", '" + imagesJson + "', " +
    esc(province) + ', ' + esc(province) + ', ' + esc(province) + ', ' +
    esc(dealerName) + ", '" + sellerType + "', 'compra', " + warranty + ', ' +
    (powerCv !== null ? String(powerCv) : 'NULL') + ', ' + (powerKw !== null ? String(powerKw) : 'NULL') + ', ' +
    "'" + rawPayload + "', NOW(), NOW(), NOW()" +
  ')';
  rows.push(row);
}

const cols = 'id, portal, url, title, brand, model, year, mileage, price, finance_price, fuel, image_url, images, city, province, location, dealer_name, seller_type, listing_type, warranty_months, power_cv, power_kw, raw_payload, first_seen_at, scraped_at, last_seen_at';

const onConflict = 'ON CONFLICT (id) DO UPDATE SET ' +
  'url = EXCLUDED.url, ' +
  'title = EXCLUDED.title, ' +
  'price = EXCLUDED.price, ' +
  'finance_price = EXCLUDED.finance_price, ' +
  'mileage = EXCLUDED.mileage, ' +
  "image_url = COALESCE(NULLIF(moveadvisor_market_offers.image_url, ''), EXCLUDED.image_url), " +
  "images = COALESCE(NULLIF(moveadvisor_market_offers.images, ''), EXCLUDED.images), " +
  'power_cv = COALESCE(EXCLUDED.power_cv, moveadvisor_market_offers.power_cv), ' +
  'power_kw = COALESCE(EXCLUDED.power_kw, moveadvisor_market_offers.power_kw), ' +
  'raw_payload = EXCLUDED.raw_payload, ' +
  'last_seen_at = NOW(), ' +
  'updated_at = NOW()';

const sql = 'INSERT INTO moveadvisor_market_offers (' + cols + ') VALUES ' + rows.join(', ') + ' ' + onConflict;

return [{ json: { sql: sql, count: items.length } }];
